function applyWebuiAppearance(){const v=state.bundle?.form_values||{},root=document.documentElement;const preset=String(v['WebUI.theme_preset']||'aurora');root.dataset.webuiPreset=preset;root.classList.toggle('liquid-glass',!!v['WebUI.liquid_glass']);const blur=Math.max(0,Math.min(40,Number(v['WebUI.background_blur']||0)));root.style.setProperty('--user-bg-blur',blur+'px');const img=String(v['WebUI.background_image']||'').trim();const bgUrl=img?(/^https?:\/\//i.test(img)?img:('/api/webui/background?token='+encodeURIComponent(token()||'')+'&v='+encodeURIComponent(img))):'';root.style.setProperty('--user-bg-image',bgUrl?`url("${bgUrl.replace(/"/g,'%22')}")`:'none');root.classList.toggle('has-bg',!!img)}
